import os
from flask import Flask, send_file, abort

app = Flask(__name__)

# This is a placeholder for your actual invoice storage path
# In a real application, you would configure this properly
INVOICE_STORAGE_PATH = "invoices"

# Ensure the invoices directory exists for demonstration
if not os.path.exists(INVOICE_STORAGE_PATH):
    os.makedirs(INVOICE_STORAGE_PATH)
    # Create some dummy invoice files for testing
    with open(os.path.join(INVOICE_STORAGE_PATH, "invoice_1.pdf"), "w") as f:
        f.write("This is a dummy invoice 1 PDF content.")
    with open(os.path.join(INVOICE_STORAGE_PATH, "invoice_2.pdf"), "w") as f:
        f.write("This is a dummy invoice 2 PDF content.")
    with open(os.path.join(INVOICE_STORAGE_PATH, "invoice_3.pdf"), "w") as f:
        f.write("This is a dummy invoice 3 PDF content.")


@app.route("/api/invoices/<int:invoice_id>/download", methods=["GET"])
def download_invoice(invoice_id):
    """
    Downloads a specific invoice by its ID.

    Assumes:
    - Authentication middleware has verified the user and their
      authorization to access this specific invoice.
    - Invoice files are stored in a designated directory.
    - Invoice files are named predictably, e.g., 'invoice_{id}.pdf'.
    """
    invoice_filename = f"invoice_{invoice_id}.pdf"
    invoice_filepath = os.path.join(INVOICE_STORAGE_PATH, invoice_filename)

    # Basic security check: prevent directory traversal
    # os.path.abspath and os.path.commonprefix can be used for more robust checks
    # For this simple case, checking existence and prefix is often sufficient.
    if not invoice_filepath.startswith(os.path.abspath(INVOICE_STORAGE_PATH)):
        abort(400, description="Invalid invoice path")

    if not os.path.exists(invoice_filepath):
        abort(404, description=f"Invoice with ID {invoice_id} not found.")

    try:
        # send_file automatically sets appropriate headers for downloads
        # like Content-Disposition and Content-Type.
        return send_file(
            invoice_filepath,
            mimetype="application/pdf",
            as_attachment=True,
            download_name=invoice_filename # Ensures the downloaded file has the correct name
        )
    except Exception as e:
        app.logger.error(f"Error serving invoice {invoice_id}: {e}")
        abort(500, description="An error occurred while trying to download the invoice.")

